const raw = $input.first().json.content[0].text;
let routing;
try {
  const match = raw.match(/\{[\s\S]*\}/);
  routing = match ? JSON.parse(match[0]) : {};
} catch(e) {
  routing = { provider_id: null, provider_name: 'MonteCarlo', match_score: 70, match_reason: 'Proveedor por defecto', routing_notes: 'Error en routing automático — asignar manualmente' };
}

const webhook = $('Webhook').first().json.body;

return [{ json: { ...routing, lead_name: webhook.name, lead_phone: webhook.phone, service_name: webhook.service_name } }];
